PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX bd: <http://www.bigdata.com/rdf#>

SELECT DISTINCT ?nomination ?nominationLabel WHERE {
  VALUES ?person { wd:Q240873 }
  ?person p:P1411 ?nomStmt.
  ?nomStmt ps:P1411 ?nomination;
           pq:P1686 ?work.
  ?work wdt:P31/wdt:P279* wd:Q11424;
        wdt:P161 wd:Q240873;
        rdfs:label ?workLabel.
  FILTER(LANG(?workLabel) IN ("es","en"))
  FILTER(LCASE(STR(?workLabel)) = "la otra")
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en,es,[AUTO_LANGUAGE]" }
}
ORDER BY ?nominationLabel

