SELECT DISTINCT ?work ?workLabel WHERE {
  ?person rdfs:label "Franz Waxman"@en ;
          wdt:P31 wd:Q5 ;
          p:P1411 ?nomStmt .
  ?nomStmt ps:P1411 ?category .
  ?category wdt:P361 ?series .
  ?series rdfs:label "Academy Awards"@en .
  ?nomStmt pq:P1686 ?work .
  ?edition rdfs:label "23rd Academy Awards"@en .
  {
    ?nomStmt pq:P642 ?edition .
