  {
    ?nomStmt pq:P585 ?nomDate .
    ?edition wdt:P585 ?ceremonyDate .
    FILTER(year(?nomDate) = year(?ceremonyDate))
  }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en" }
}

