PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX psv: <http://www.wikidata.org/prop/statement/value/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?amount ?unit ?source WHERE {
  {
    wd:Q193 ?p ?st .
    ?prop wikibase:claim ?p ;
          wikibase:statementValue ?psv ;
          rdfs:label ?propLabel .
    FILTER(LANG(?propLabel) = "en" && LCASE(STR(?propLabel)) = "bond albedo")
    ?st ?psv ?vnode .
    ?vnode wikibase:quantityAmount ?amount ;
           wikibase:quantityUnit ?unit .
    BIND("Bond albedo property" AS ?source)
  }
  UNION
  {
    wd:Q193 ?p ?st .
    ?prop wikibase:claim ?p ;
          wikibase:statementValue ?psv ;
          rdfs:label ?propLabel .
    FILTER(LANG(?propLabel) = "en" && LCASE(STR(?propLabel)) = "albedo")
    ?st ?psv ?vnode .
    ?vnode wikibase:quantityAmount ?amount ;
           wikibase:quantityUnit ?unit .
    ?st ?anyQualProp ?qualVal .
    ?qualVal rdfs:label ?qLabel .
    FILTER(LANG(?qLabel) = "en" && CONTAINS(LCASE(?qLabel), "bond albedo"))
    BIND("Albedo with qualifier Bond albedo" AS ?source)
  }
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
PREFIX wikibase: <http://wikiba.se/ontology#>
