SELECT DISTINCT ?item ?itemLabel WHERE {
  VALUES ?dType { wd:Q11862829 wd:Q246188 }
  ?item (wdt:P31/wdt:P279* | wdt:P279*) ?dType .
  {
    ?item rdfs:label ?label .
    FILTER(REGEX(LCASE(STR(?label)), "v(ö|oe|o)lkerpsychologie"))
  }
  UNION
  {
    ?item skos:altLabel ?alt .
    FILTER(REGEX(LCASE(STR(?alt)), "v(ö|oe|o)lkerpsychologie"))
  }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en,de" }
}
ORDER BY ?itemLabel

