SELECT DISTINCT ?city ?cityLabel WHERE {
  VALUES ?neworleans { wd:Q34404 }
  {
    ?neworleans p:P190 ?st .
    ?st ps:P190 ?city ;
        ?qualProp ?date .
    VALUES ?qualProp { pq:P580 pq:P585 }
    FILTER(YEAR(?date) = 2012)
  }
  UNION
  {
    ?city p:P190 ?st2 .
    ?st2 ps:P190 ?neworleans ;
         ?qualProp2 ?date2 .
    VALUES ?qualProp2 { pq:P580 pq:P585 }
    FILTER(YEAR(?date2) = 2012)
  }
  ?city wdt:P31/wdt:P279* wd:Q515 .
