  ?arsenic rdfs:label "arsenic"@en .

  # Find the property whose English label starts with "time-weighted average exposure limit"
  ?prop a wikibase:Property ;
        rdfs:label ?propLabel ;
        wikibase:statementProperty ?p ;
        wikibase:statementValue ?psv .
