  # Get the quantity value (amount and unit)
  ?arsenic ?p ?st .
  ?st ?psv ?qv .
  ?qv wikibase:quantityAmount ?amount ;
      wikibase:quantityUnit ?unit .

  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

