SELECT ?phase ?phaseLabel ?pressure WHERE {
  VALUES ?phase { wd:Q11469 wd:Q283 wd:Q190078 }  # ice, water (liquid), water vapor

  # find the item for the triple point of water
  ?tp rdfs:label ?tpLabel .
  FILTER(LANG(?tpLabel) = "en").
  FILTER(CONTAINS(LCASE(?tpLabel), "triple point") && CONTAINS(LCASE(?tpLabel), "water")) .

  # find the numeric property labeled exactly "pressure" and use its direct claim to get the value
  ?prop a wikibase:Property ;
        rdfs:label ?propLabel ;
        wikibase:propertyType wikibase:Quantity ;
        wikibase:directClaim ?wdProp .
  FILTER(LANG(?propLabel) = "en" && STR(?propLabel) = "pressure").

  ?tp ?wdProp ?pressure .

  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

