  } UNION {
    wd:Q46901 wdt:P355 ?division .
  } UNION {
    wd:Q46901 wdt:P527 ?division .
  }

  # Identify the "commerce" division by label/alias/description
  {
    ?division (rdfs:label|skos:altLabel) ?name .
    FILTER(LANG(?name) = "en" && CONTAINS(LCASE(?name), "commerce"))
  } UNION {
    ?division schema:description ?desc .
    FILTER(LANG(?desc) = "en" && CONTAINS(LCASE(?desc), "commerce"))
  }

  # Find any property labeled "carrier" and get its value for that division
  ?prop a wikibase:Property ;
        rdfs:label ?propLabel ;
        wikibase:directClaim ?dcProp .
  FILTER(LANG(?propLabel) = "en" && CONTAINS(LCASE(?propLabel), "carrier")) .

  ?division ?dcProp ?carrier .

  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en" }
}

