PREFIX bd: <http://www.bigdata.com/rdf#>
PREFIX mwapi: <https://www.mediawiki.org/ontology#API/>

SELECT ?value ?unitLabel WHERE {
  SERVICE wikibase:mwapi {
    bd:serviceParam wikibase:endpoint "www.wikidata.org" ;
                    wikibase:api "EntitySearch" ;
                    mwapi:search "2,4,6-trinitrotoluene" ;
                    mwapi:language "en" .
    ?item wikibase:apiOutputItem mwapi:item .
  }
  ?prop a wikibase:Property ; rdfs:label ?propLabel .
  FILTER(?propLabel IN ("detonation velocity"@en, "explosive velocity"@en))
  ?prop wikibase:claim ?pClaim ;
        wikibase:statementValue ?pStatementValue .
  ?item ?pClaim ?stmt .
  ?stmt ?pStatementValue ?valNode .
  ?valNode wikibase:quantityAmount ?value ;
           wikibase:quantityUnit ?unit .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
ORDER BY ?value

