PREFIX mwapi: <https://www.mediawiki.org/ontology#API/>

SELECT DISTINCT ?player ?playerLabel WHERE {
  # Find the work by title (either given phrasing or the common English title)
  VALUES ?searchTitle { "Dark Girl/White Young lady" "Black Girl/White Girl" }
  SERVICE wikibase:mwapi {
    bd:serviceParam wikibase:endpoint "www.wikidata.org" ;
                    wikibase:api "EntitySearch" ;
                    mwapi:search ?searchTitle ;
                    mwapi:language "en" .
    ?work wikibase:apiOutputItem mwapi:item .
  }
  # Restrict to books/novels and get its author
  ?work wdt:P31/wdt:P279* ?cls ;
        wdt:P50 ?author .
  VALUES ?cls { wd:Q8261 wd:Q571 }

  # Find the property for "favorite/favourite player"
  VALUES ?favSearch { "favorite player" "favourite player" }
  SERVICE wikibase:mwapi {
    bd:serviceParam wikibase:endpoint "www.wikidata.org" ;
                    wikibase:api "EntitySearch" ;
                    mwapi:search ?favSearch ;
                    mwapi:language "en" ;
                    mwapi:type "property" .
    ?prop wikibase:apiOutputItem mwapi:item .
  }
  ?prop wikibase:directClaim ?favProp .

  # Author's favorite player
  ?author ?favProp ?player .
  ?player wdt:P31 wd:Q5 .

  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en" }
}

