    ?person wdt:P25 ?relative .
    BIND(wd:P25 AS ?relationProp)
  } UNION {
    ?person wdt:P40 ?relative .
    BIND(wd:P40 AS ?relationProp)
  } UNION {
    ?person wdt:P26 ?relative .
    BIND(wd:P26 AS ?relationProp)
  } UNION {
    ?person wdt:P3373 ?relative .
    BIND(wd:P3373 AS ?relationProp)
  } UNION {
    ?person wdt:P451 ?relative .
    BIND(wd:P451 AS ?relationProp)
  } UNION {
    ?person wdt:P1038 ?relative .
    BIND(wd:P1038 AS ?relationProp)
