PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>

SELECT DISTINCT ?personLabel WHERE {
  # the film
  ?film wdt:P31/wdt:P279* wd:Q11424;
        rdfs:label "Eternal Sunshine of the Spotless Mind"@en.

  # the award category (handle label variants)
  ?award (rdfs:label|skos:altLabel) ?al.
  FILTER(LANG(?al) = "en" && REGEX(?al, "Academy Award.*Original Screenplay", "i"))

  {
    ?person wdt:P31 wd:Q5;
            p:P1411 ?nomStmt.
    ?nomStmt ps:P1411 ?award;
             pq:P1686 ?film.
  }
  UNION
  {
    ?person wdt:P31 wd:Q5;
            p:P166 ?winStmt.
    ?winStmt ps:P166 ?award;
             pq:P1686 ?film.
  }

  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

