  ?work rdfs:label "Ishaqzaade"@en ;
        wdt:P31/wdt:P279* wd:Q11424 .
  ?character wdt:P1441 ?work ;
             wdt:P175 ?actor .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT DISTINCT ?work ?workLabel ?publisher ?publisherLabel WHERE {
  {
    SELECT ?work WHERE {
      ?person rdfs:label "Christopher Hitchens"@en.
      ?person wdt:P31 wd:Q5.
      ?person p:P800 ?stmt.
      ?stmt ps:P800 ?work.
      ?work wikibase:sitelinks ?sitelinks.
    }
    ORDER BY DESC(?sitelinks)
    LIMIT 1
  }
  OPTIONAL { ?work wdt:P123 ?publisher. }
  OPTIONAL {
    ?edition wdt:P629 ?work;
             wdt:P123 ?publisher.
  }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

