PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX psv: <http://www.wikidata.org/prop/statement/value/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX bd: <http://www.bigdata.com/rdf#>

SELECT ?u ?uLabel ?amount ?unitLabel WHERE {
  # U-boats (incl. classes) operated by the Kriegsmarine (WWII era)
  ?u wdt:P31/wdt:P279* wd:Q169128 ;
     wdt:P137 wd:Q17294 .

  # Find a quantity property whose English label contains "range"
  ?prop a wikibase:Property ;
        rdfs:label ?pLabel ;
        wikibase:propertyType wikibase:Quantity ;
        wikibase:claim ?pClaim ;
        wikibase:statementValue ?psvProp .
  FILTER(LANG(?pLabel) = "en" && CONTAINS(LCASE(?pLabel), "range"))

  # Get the quantity value (amount + unit)
  ?u ?pClaim ?st .
  ?st ?psvProp ?valNode .
  ?valNode wikibase:quantityAmount ?amount ;
          wikibase:quantityUnit ?unit .

  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en" }
}
ORDER BY ?amount
LIMIT 1

