           wikibase:statementValue ?smaStatementValue .
  ?mars ?smaClaim ?smaStatement .
  ?smaStatement ?smaStatementValue ?smaNode .
  ?smaNode wikibase:quantityAmount ?smaAmount ;
           wikibase:quantityUnit ?smaUnit .
  FILTER(
    (?smaUnit = wd:Q181898 && abs(?smaAmount - 1.524) <= 0.01) ||
    (?smaUnit = wd:Q11573  && abs(?smaAmount - 228000000) <= 1000000)
  )

  # eccentricity ≈ 0.0934
  ?propEcc a wikibase:Property ; rdfs:label "orbital eccentricity"@en ;
           wikibase:directClaim ?eccPred .
  ?mars ?eccPred ?ecc .
  FILTER(abs(?ecc - 0.0934) <= 0.001)

  # orbital period ≈ 687 days
  ?propPeriod a wikibase:Property ; rdfs:label "orbital period"@en ;
              wikibase:claim ?perClaim ;
              wikibase:statementValue ?perStatementValue .
  ?mars ?perClaim ?perStatement .
  ?perStatement ?perStatementValue ?perNode .
  ?perNode wikibase:quantityAmount ?perAmount ;
           wikibase:quantityUnit ?perUnit .
  FILTER(?perUnit = wd:Q573 && abs(?perAmount - 687) <= 2)

  # orbits the Sun
  ?propParent a wikibase:Property ; rdfs:label "parent astronomical body"@en ;
              wikibase:directClaim ?parentPred .
  ?mars ?parentPred wd:Q525 .
}

