PREFIX mwapi: <https://www.mediawiki.org/wiki/MediaWiki_API#>

SELECT ?seat ?seatLabel WHERE {
  # Find the village/settlement "Acacoyagua"
  SERVICE wikibase:mwapi {
    bd:serviceParam wikibase:endpoint "www.wikidata.org";
    bd:serviceParam wikibase:api "EntitySearch";
    bd:serviceParam mwapi:search "Acacoyagua";
    bd:serviceParam mwapi:language "en".
    ?place wikibase:apiOutputItem mwapi:item.
  }
  ?place wdt:P31/wdt:P279* wd:Q486972.

  # Find its containing municipality in Mexico and its seat (county seat)
  ?place wdt:P131+ ?muni.
  ?muni wdt:P31/wdt:P279* wd:Q15284;
        wdt:P17 wd:Q96;
        wdt:P36 ?seat.

  # Identify the state whose capital is Tuxtla Gutiérrez
  SERVICE wikibase:mwapi {
    bd:serviceParam wikibase:endpoint "www.wikidata.org";
    bd:serviceParam wikibase:api "EntitySearch";
    bd:serviceParam mwapi:search "Tuxtla Gutiérrez";
    bd:serviceParam mwapi:language "en".
    ?tuxtla wikibase:apiOutputItem mwapi:item.
  }
  ?tuxtla wdt:P31/wdt:P279* wd:Q486972.
  ?state wdt:P36 ?tuxtla.

  # Ensure the municipality is within that state
  ?muni wdt:P131+ ?state.

  SERVICE wikibase:label { bd:serviceParam wikibase:language "en,es" }
}

